using Microsoft.Data.Sqlite;
using woOshLaundrySystem.Enums;
using woOshLaundrySystem.Models;
namespace woOshLaundrySystem.Data;
public class OrderRepository
{
    public int Add(LaundryOrder o){using var c=DatabaseHelper.GetConnection();c.Open();using var tx=c.BeginTransaction();using var cmd=c.CreateCommand();cmd.Transaction=tx;cmd.CommandText=@"INSERT INTO LaundryOrders(OrderNumber,CustomerId,ReceivedAt,EstimatedFinishAt,ProcessingMode,ServiceType,ServiceSpeed,OrderStatus,PaymentStatus,AppliedPackageId,ReceiverEmployeeId,ResponsibleEmployeeId,RegularSubtotal,PackageCoveredWeight,AmountDueNow,Notes) VALUES(@no,@cu,@ra,@ef,@pm,@st,@ss,@os,@ps,@ap,@re,@rw,@rs,@pc,@ad,@n); SELECT last_insert_rowid();";cmd.Parameters.AddWithValue("@no",o.OrderNumber);cmd.Parameters.AddWithValue("@cu",o.CustomerId);cmd.Parameters.AddWithValue("@ra",o.ReceivedAt.ToString("s"));cmd.Parameters.AddWithValue("@ef",o.EstimatedFinishAt.ToString("s"));cmd.Parameters.AddWithValue("@pm",o.ProcessingMode.ToString());cmd.Parameters.AddWithValue("@st",o.ServiceType.ToString());cmd.Parameters.AddWithValue("@ss",o.ServiceSpeed.ToString());cmd.Parameters.AddWithValue("@os",o.OrderStatus.ToString());cmd.Parameters.AddWithValue("@ps",o.PaymentStatus.ToString());cmd.Parameters.AddWithValue("@ap",(object?)o.AppliedPackageId??DBNull.Value);cmd.Parameters.AddWithValue("@re",o.Assignment.ReceiverEmployeeId);cmd.Parameters.AddWithValue("@rw",o.Assignment.ResponsibleEmployeeId);cmd.Parameters.AddWithValue("@rs",o.Pricing.RegularSubtotal);cmd.Parameters.AddWithValue("@pc",o.Pricing.PackageCoveredWeight);cmd.Parameters.AddWithValue("@ad",o.Pricing.AmountDueNow);cmd.Parameters.AddWithValue("@n",o.Notes);var id=Convert.ToInt32(cmd.ExecuteScalar());foreach(var d in o.Details){using var dc=c.CreateCommand();dc.Transaction=tx;dc.CommandText=@"INSERT INTO OrderDetails(OrderId,ItemCategory,ItemName,UnitType,WeightKg,Quantity,IsPackageEligible,IsCoveredByPackage,RegularSubtotal,Notes) VALUES(@o,@ic,@in,@u,@w,@q,@pe,@pc,@r,@n)";dc.Parameters.AddWithValue("@o",id);dc.Parameters.AddWithValue("@ic",d.ItemCategory.ToString());dc.Parameters.AddWithValue("@in",d.ItemName);dc.Parameters.AddWithValue("@u",d.UnitType.ToString());dc.Parameters.AddWithValue("@w",(object?)d.WeightKg??DBNull.Value);dc.Parameters.AddWithValue("@q",(object?)d.Quantity??DBNull.Value);dc.Parameters.AddWithValue("@pe",d.IsPackageEligible?1:0);dc.Parameters.AddWithValue("@pc",d.IsCoveredByPackage?1:0);dc.Parameters.AddWithValue("@r",d.RegularSubtotal);dc.Parameters.AddWithValue("@n",d.Notes);dc.ExecuteNonQuery();}tx.Commit();return id;}
    public List<LaundryOrder> GetAll(string status=""){var list=new List<LaundryOrder>();using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText=string.IsNullOrWhiteSpace(status)||status=="Semua"?"SELECT * FROM LaundryOrders ORDER BY OrderId DESC":"SELECT * FROM LaundryOrders WHERE OrderStatus=@s ORDER BY OrderId DESC";if(!string.IsNullOrWhiteSpace(status)&&status!="Semua")cmd.Parameters.AddWithValue("@s",status);using var r=cmd.ExecuteReader();while(r.Read())list.Add(MapOrder(r));return list;}
    public LaundryOrder? GetById(int id){using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="SELECT * FROM LaundryOrders WHERE OrderId=@id";cmd.Parameters.AddWithValue("@id",id);using var r=cmd.ExecuteReader();var o=r.Read()?MapOrder(r):null;if(o!=null)o.Details=GetDetails(id);return o;}
    public List<OrderDetail> GetDetails(int id){var list=new List<OrderDetail>();using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="SELECT * FROM OrderDetails WHERE OrderId=@id";cmd.Parameters.AddWithValue("@id",id);using var r=cmd.ExecuteReader();while(r.Read())list.Add(new OrderDetail{OrderDetailId=r.GetInt32(0),OrderId=r.GetInt32(1),ItemCategory=Enum.Parse<LaundryItemCategory>(r.GetString(2)),ItemName=r.GetString(3),UnitType=Enum.Parse<UnitType>(r.GetString(4)),WeightKg=r.IsDBNull(5)?null:r.GetDouble(5),Quantity=r.IsDBNull(6)?null:r.GetInt32(6),IsPackageEligible=r.GetInt32(7)==1,IsCoveredByPackage=r.GetInt32(8)==1,RegularSubtotal=r.GetInt32(9),Notes=r.IsDBNull(10)?"":r.GetString(10)});return list;}
    public void UpdateStatus(int id,OrderStatus s){using var c=DatabaseHelper.GetConnection();c.Open();using var cmd=c.CreateCommand();cmd.CommandText="UPDATE LaundryOrders SET OrderStatus=@s WHERE OrderId=@id";cmd.Parameters.AddWithValue("@s",s.ToString());cmd.Parameters.AddWithValue("@id",id);cmd.ExecuteNonQuery();}
    LaundryOrder MapOrder(SqliteDataReader r)=>new(){OrderId=r.GetInt32(0),OrderNumber=r.GetString(1),CustomerId=r.GetInt32(2),ReceivedAt=DateTime.Parse(r.GetString(3)),EstimatedFinishAt=DateTime.Parse(r.GetString(4)),ProcessingMode=Enum.Parse<ProcessingMode>(r.GetString(5)),ServiceType=Enum.Parse<ServiceType>(r.GetString(6)),ServiceSpeed=Enum.Parse<ServiceSpeed>(r.GetString(7)),OrderStatus=Enum.Parse<OrderStatus>(r.GetString(8)),PaymentStatus=Enum.Parse<PaymentStatus>(r.GetString(9)),AppliedPackageId=r.IsDBNull(10)?null:r.GetInt32(10),Assignment=new OrderAssignment{ReceiverEmployeeId=r.GetInt32(11),ResponsibleEmployeeId=r.GetInt32(12)},Pricing=new PricingBreakdown{RegularSubtotal=r.GetInt32(13),PackageCoveredWeight=r.GetDouble(14),AmountDueNow=r.GetInt32(15)},Notes=r.IsDBNull(16)?"":r.GetString(16)};
}